#include <iostream>
#include <unordered_map>

struct User {
    int id;
    std::string name;
    std::string email;
};

User* getUserProfile(int userId, std::unordered_map<int, User>& userTable) {
    auto it = userTable.find(userId);
    if (it != userTable.end()) {
        return &it->second;
    }
    return nullptr;
}

int main() {
    std::unordered_map<int, User> userTable = {
        {1, {1, "Alice", "alice@example.com"}},
        {2, {2, "Bob", "bob@example.com"}}
    };

    int userId = 1;
    User* userProfile = getUserProfile(userId, userTable);
    if (userProfile) {
        std::cout << "User ID: " << userProfile->id << ", Name: " << userProfile->name << ", Email: " << userProfile->email << std::endl;
    } else {
        std::cout << "User not found" << std::endl;
    }

    return 0;
}